p.m:
\displaystyle{\begin{aligned}
   40\div \frac{8}{5} 
       \amp = \frac{40}{1} \div \frac{8}{5} \\
       \amp = \frac{40}{1} \cdot \frac{5}{8} \amp \hbox{We can divide 40 and 8 by 8 and made those two values smaller.}\\
       \amp = \frac{5}{1}\cdot\frac{5}{1} \\
       \amp = \frac{5\cdot5}{1 \cdot 1} \\
       \amp = 25
\end{aligned}
    }
